import{_ as e}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{o as r,c as o,af as a}from"./chunks/runtime-core.esm-bundler.p2kBHoTO.js";const m=JSON.parse('{"title":"IDEF0 Editor — браузерный редактор функциональных диаграмм","description":"Как устроен IDEF0 Editor: реактивная модель на Vue 3, SVG-стрелки с манхэттенской маршрутизацией, декомпозиция по иерархии и валидация ICOM по FIPS 183. Локально, без облака.","frontmatter":{"title":"IDEF0 Editor — браузерный редактор функциональных диаграмм","description":"Как устроен IDEF0 Editor: реактивная модель на Vue 3, SVG-стрелки с манхэттенской маршрутизацией, декомпозиция по иерархии и валидация ICOM по FIPS 183. Локально, без облака.","head":[["link",{"rel":"canonical","href":"https://alterfo.github.io/projects/idef0-editor"}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:title","content":"IDEF0 Editor — браузерный редактор функциональных диаграмм"}],["meta",{"property":"og:description","content":"Как устроен IDEF0 Editor: реактивная модель на Vue 3, SVG-стрелки с манхэттенской маршрутизацией, декомпозиция по иерархии и валидация ICOM по FIPS 183. Локально, без облака."}],["meta",{"property":"og:url","content":"https://alterfo.github.io/projects/idef0-editor"}],["meta",{"property":"og:image","content":"https://alterfo.github.io/og.png"}],["meta",{"property":"og:site_name","content":"Alterfo"}],["meta",{"property":"og:locale","content":"ru_RU"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"IDEF0 Editor — браузерный редактор функциональных диаграмм"}],["meta",{"name":"twitter:description","content":"Как устроен IDEF0 Editor: реактивная модель на Vue 3, SVG-стрелки с манхэттенской маршрутизацией, декомпозиция по иерархии и валидация ICOM по FIPS 183. Локально, без облака."}],["meta",{"name":"twitter:image","content":"https://alterfo.github.io/og.png"}]]},"headers":[],"relativePath":"projects/idef0-editor.md","filePath":"projects/idef0-editor.md"}'),i={name:"projects/idef0-editor.md"};function n(s,t,d,l,h,c){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="idef0-editor-—-функциональное-моделирование-в-браузере" tabindex="-1">IDEF0 Editor — функциональное моделирование в браузере <a class="header-anchor" href="#idef0-editor-—-функциональное-моделирование-в-браузере" aria-label="Permalink to &quot;IDEF0 Editor — функциональное моделирование в браузере&quot;">​</a></h1><p><strong>IDEF0 Editor</strong> — это редактор функциональных диаграмм, который целиком работает в браузере: ничего не нужно ставить, регистрироваться или загружать на чужой сервер. Вы рисуете блоки-функции, тянете между ними стрелки, разбиваете крупную функцию на подфункции — и всё это сохраняется прямо на вашем устройстве.</p><p>→ <strong><a href="/idef0.html">Открыть редактор</a></strong></p><h2 id="что-такое-idef0" tabindex="-1">Что такое IDEF0 <a class="header-anchor" href="#что-такое-idef0" aria-label="Permalink to &quot;Что такое IDEF0&quot;">​</a></h2><p>IDEF0 — это стандарт описания процессов через функциональные блоки. Каждый блок — это действие («Обработать заявку», «Собрать отчёт»), а стрелки вокруг него — это <strong>ICOM</strong>: <strong>I</strong>nput (вход слева), <strong>C</strong>ontrol (управление сверху), <strong>O</strong>utput (выход справа) и <strong>M</strong>echanism (механизм снизу). Сложную функцию можно «провалить» в дочернюю диаграмму и расписать подробнее — так строится иерархия от общего к частному. Редактор следует американскому федеральному стандарту <strong>FIPS 183</strong>, поэтому диаграммы получаются формально корректными, а не просто «коробочки со стрелочками».</p><h2 id="зачем-браузерныи-и-локальныи" tabindex="-1">Зачем браузерный и локальный <a class="header-anchor" href="#зачем-браузерныи-и-локальныи" aria-label="Permalink to &quot;Зачем браузерный и локальный&quot;">​</a></h2><p>Большинство инструментов моделирования — это либо тяжёлые десктопные программы, либо облачные сервисы, куда схема процессов утекает на чужие серверы. А диаграмма процессов часто описывает внутреннюю кухню компании — то, что не хочется отдавать наружу. Отсюда два принципа: <strong>никакой установки</strong> (открыл вкладку — работаешь) и <strong>данные не покидают устройство</strong> (всё лежит в IndexedDB браузера, синхронизация между вкладками идёт локально). Бонусом — никакого CDN и сторонних API: редактор построен на нативных браузерных возможностях.</p><h2 id="как-это-устроено" tabindex="-1">Как это устроено <a class="header-anchor" href="#как-это-устроено" aria-label="Permalink to &quot;Как это устроено&quot;">​</a></h2><p>Я переписал редактор с canvas на связку <strong>SVG + Vue 3</strong>, строго по FIPS 183. Архитектура разбита на независимые модули с чистыми функциями — так логику легко тестировать и менять.</p><h3 id="реактивная-модель" tabindex="-1">Реактивная модель <a class="header-anchor" href="#реактивная-модель" aria-label="Permalink to &quot;Реактивная модель&quot;">​</a></h3><p>Всё состояние — проект, диаграммы, блоки и стрелки — живёт в реактивных структурах Vue 3 (<code>ref</code>/<code>reactive</code>). Любое изменение модели автоматически перерисовывает SVG, без ручного обновления DOM. Рендер — это набор <strong>чистых функций</strong>, которые по данным блока или стрелки отдают объект SVG-атрибутов; сам Vue уже превращает их в элементы.</p><h3 id="стрелки-с-манхэттенскои-маршрутизациеи" tabindex="-1">Стрелки с манхэттенской маршрутизацией <a class="header-anchor" href="#стрелки-с-манхэттенскои-маршрутизациеи" aria-label="Permalink to &quot;Стрелки с манхэттенской маршрутизацией&quot;">​</a></h3><p>Стрелки рисуются не по прямой, а <strong>под прямыми углами</strong> (манхэттенская маршрутизация): минимум два сегмента, повороты только на 90°, наконечник — залитый треугольник. Внутренние связи сплошные, граничные (выходящие за пределы диаграммы) — пунктирные, с подписью кода ICOM (I1, C1, O1, M1) в точке привязки к краю. Когда блок перетаскивают, маршрут стрелки пересчитывается на лету.</p><h3 id="хранение-и-синхронизация" tabindex="-1">Хранение и синхронизация <a class="header-anchor" href="#хранение-и-синхронизация" aria-label="Permalink to &quot;Хранение и синхронизация&quot;">​</a></h3><p>Проект автосохраняется в <strong>IndexedDB</strong> с дебаунсом 300 мс — частые правки не молотят диск зря. Если открыто несколько вкладок, изменения разъезжаются между ними через событие <code>localStorage</code>, так что вторая вкладка подхватывает свежую версию. Экспорт — в SVG, PNG (×2) и JSON; импорт JSON восстанавливает проект целиком.</p><h2 id="что-было-интересно-решить" tabindex="-1">Что было интересно решить <a class="header-anchor" href="#что-было-интересно-решить" aria-label="Permalink to &quot;Что было интересно решить&quot;">​</a></h2><ul><li><strong>Маршрутизация стрелок.</strong> Заставить L-образные стрелки выглядеть аккуратно при любом расположении блоков и честно перестраиваться при перетаскивании — это отдельная пачка геометрии, вынесенная в чистый модуль рендера.</li><li><strong>Иерархия и декомпозиция.</strong> Блок можно «провалить» в дочернюю диаграмму, и у неё своя схема нумерации узлов (A0 → A1 → A11…), хлебные крошки для навигации и обратный путь наверх. Удаление декомпозиции рекурсивно вычищает всё поддерево дочерних диаграмм, а не оставляет висячие ссылки.</li><li><strong>Валидация ICOM по FIPS 183.</strong> Стандарт задаёт жёсткие правила: вход входит слева, выход выходит справа, управление — сверху, механизм — снизу, вызов (CALL) — снизу наружу. Отдельный модуль проверяет диаграмму на эти правила и подсвечивает нарушившие блоки красной рамкой, а список ошибок показывает в боковой панели.</li><li><strong>Отмена/повтор.</strong> Undo/redo построены на снимках состояния (до 50 шагов, Ctrl+Z / Ctrl+Y) и сбрасываются при переходе между диаграммами, чтобы история не путалась между уровнями иерархии.</li></ul><h2 id="текущее-состояние" tabindex="-1">Текущее состояние <a class="header-anchor" href="#текущее-состояние" aria-label="Permalink to &quot;Текущее состояние&quot;">​</a></h2><p>Работает полный цикл: автораскладка по диагонали (FIPS 183), drag-and-drop блоков, рисование стрелок через всплывающие «ручки» на сторонах блока с выбором типа ICOM, инлайн-редактирование подписей по двойному клику, декомпозиция с навигацией по хлебным крошкам, панель валидации, отмена/повтор, автосохранение с межвкладочной синхронизацией и экспорт в SVG/PNG/JSON. Логика модели покрыта юнит-тестами; визуальная часть проверяется вручную в браузере.</p><p>→ Попробовать самому: <strong><a href="/idef0.html">/idef0</a></strong></p><h2 id="из-блога" tabindex="-1">Из блога <a class="header-anchor" href="#из-блога" aria-label="Permalink to &quot;Из блога&quot;">​</a></h2><ul><li><a href="/posts/2020-10-05-SDLC.html">Жизненный цикл разработки (SDLC)</a> — про процессы, которые IDEF0 и помогает описывать.</li><li><a href="/posts/2022-12-24-stack-2-maintainability-reliability.html">Выбор стека технологий: поддерживаемость</a> — почему правильная структура решает, что в коде, что в процессах.</li></ul>',22)])])}const u=e(i,[["render",n]]);export{m as __pageData,u as default};
